import { Component, inject, OnInit, OnDestroy, ViewChild, ElementRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AudioService } from '../../services/audio.service';
import { ChatService } from '../../services/chat.service';
import { AgentService } from '../../services/agent.service';
import { Subscription } from 'rxjs';

interface VoiceState {
  isListening: boolean;
  isProcessing: boolean;
  isSpeaking: boolean;
  transcript: string;
  partialTranscript: string;
  confidence: number;
}

@Component({
  selector: 'app-voice-assistant',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './voice-assistant.component.html',
  styleUrls: ['./voice-assistant.component.css']
})
export class VoiceAssistantComponent implements OnInit, OnDestroy {
  audioService = inject(AudioService);
  chatService = inject(ChatService);
  agentService = inject(AgentService);

  @ViewChild('audioVisualizer') audioVisualizer!: ElementRef<HTMLDivElement>;

  voiceState: VoiceState = {
    isListening: false,
    isProcessing: false,
    isSpeaking: false,
    transcript: '',
    partialTranscript: '',
    confidence: 0
  };

  isSupported = false;
  autoSpeak = true;
  autoSend = true;
  sendDelay = 2000; // ms
  private sendTimer: any = null;
  private subscriptions: Subscription[] = [];

  ngOnInit() {
    this.isSupported = this.audioService.isSpeechRecognitionSupported();

    // Subscribe to audio state changes
    this.subscriptions.push(
      this.audioService.audioState$.subscribe(state => {
        this.voiceState.isListening = state.isRecording;
        this.voiceState.isProcessing = state.isProcessing;
        this.voiceState.transcript = state.transcript;
        this.voiceState.confidence = state.confidence;
      })
    );

    // Subscribe to partial transcripts for real-time feedback
    this.subscriptions.push(
      this.audioService.partialTranscript$.subscribe(transcript => {
        this.voiceState.partialTranscript = transcript;
      })
    );

    // Subscribe to final transcripts for auto-processing
    this.subscriptions.push(
      this.audioService.finalTranscript$.subscribe(transcript => {
        this.handleFinalTranscript(transcript);
      })
    );

    // Subscribe to errors
    this.subscriptions.push(
      this.audioService.error$.subscribe(error => {
        console.error('Audio error:', error);
      })
    );
  }

  ngOnDestroy() {
    this.subscriptions.forEach(sub => sub.unsubscribe());
    this.clearSendTimer();
    if (this.voiceState.isListening) {
      this.audioService.stopRecording();
    }
  }

  async toggleListening() {
    if (this.voiceState.isListening) {
      this.stopListening();
    } else {
      await this.startListening();
    }
  }

  async startListening() {
    try {
      this.audioService.clearTranscript();
      this.voiceState.transcript = '';
      this.voiceState.partialTranscript = '';
      await this.audioService.startContinuousRecording();
    } catch (error) {
      console.error('Error starting listening:', error);
    }
  }

  stopListening() {
    this.audioService.stopRecording();
    this.clearSendTimer();
  }

  private handleFinalTranscript(transcript: string) {
    if (!transcript.trim()) return;

    // Update transcript
    this.voiceState.transcript += transcript;
    this.voiceState.partialTranscript = '';

    // Auto-send logic
    if (this.autoSend && this.shouldAutoSend(transcript)) {
      this.scheduleSend();
    }
  }

  private shouldAutoSend(transcript: string): boolean {
    const trimmed = transcript.trim();

    // Send if it's a complete sentence
    if (trimmed.endsWith('.') || trimmed.endsWith('?') || trimmed.endsWith('!')) {
      return true;
    }

    // Send if it's a short command
    if (trimmed.length < 20 && this.isCommand(trimmed)) {
      return true;
    }

    // Send if there's a pause (handled by timer)
    return false;
  }

  private isCommand(text: string): boolean {
    const commands = [
      'bonjour', 'salut', 'merci', 'au revoir', 'aide', 'help',
      'arrête', 'stop', 'pause', 'continue', 'recommence'
    ];
    return commands.some(cmd => text.toLowerCase().includes(cmd));
  }

  private scheduleSend() {
    this.clearSendTimer();
    this.sendTimer = setTimeout(() => {
      this.sendMessage();
    }, this.sendDelay);
  }

  private clearSendTimer() {
    if (this.sendTimer) {
      clearTimeout(this.sendTimer);
      this.sendTimer = null;
    }
  }

  private async sendMessage() {
    const message = this.voiceState.transcript.trim();
    if (!message) return;

    // Create session if needed
    let sessionId = this.chatService.activeSessionId();
    if (!sessionId) {
      const s = this.chatService.createSession();
      sessionId = s.id;
    }

    // Add user message
    this.chatService.addMessage(sessionId, {
      role: 'user',
      text: message,
      timestamp: new Date()
    });

    // Add AI placeholder
    this.chatService.addMessage(sessionId, {
      role: 'ai',
      text: '',
      timestamp: new Date(),
      isTyping: true
    });

    // Process with AI
    this.voiceState.isProcessing = true;

    const obs = this.agentService.askQuestion(message);

    obs.subscribe({
      next: (chunk: string) => {
        this.chatService.appendToLastAiMessage(sessionId!, chunk);
      },
      error: () => {
        this.chatService.appendToLastAiMessage(
          sessionId!,
          '❌ Erreur de connexion. Vérifiez que le serveur Spring Boot est lancé sur le port 8080.'
        );
        this.voiceState.isProcessing = false;
      },
      complete: async () => {
        this.chatService.updateLastAiTyping(sessionId!, false);
        this.voiceState.isProcessing = false;

        // Auto-speak response if enabled
        if (this.autoSpeak) {
          const session = this.chatService.activeSession;
          const lastMessage = session?.messages?.slice(-1)[0];
          if (lastMessage?.text) {
            await this.speakResponse(lastMessage.text);
          }
        }

        // Clear transcript for next message
        this.audioService.clearTranscript();
        this.voiceState.transcript = '';
        this.voiceState.partialTranscript = '';
      }
    });
  }

  async speakResponse(text: string) {
    if (!this.audioService.isSpeechSynthesisSupported()) return;

    try {
      this.voiceState.isSpeaking = true;
      await this.audioService.speakSmart(text);
    } catch (error) {
      console.error('Error speaking:', error);
    } finally {
      this.voiceState.isSpeaking = false;
    }
  }

  stopSpeaking() {
    this.audioService.stopSpeaking();
    this.voiceState.isSpeaking = false;
  }

  sendNow() {
    this.clearSendTimer();
    this.sendMessage();
  }

  clearTranscript() {
    this.audioService.clearTranscript();
    this.voiceState.transcript = '';
    this.voiceState.partialTranscript = '';
    this.clearSendTimer();
  }

  getVoiceIcon(): string {
    if (this.voiceState.isSpeaking) return 'bi-volume-up-fill text-success';
    if (this.voiceState.isListening) return 'bi-mic-fill text-danger';
    if (this.voiceState.isProcessing) return 'bi-cpu text-warning';
    return 'bi-mic text-secondary';
  }

  getVoiceStatus(): string {
    if (this.voiceState.isSpeaking) return 'En cours de lecture...';
    if (this.voiceState.isListening) return 'Écoute en cours...';
    if (this.voiceState.isProcessing) return 'Traitement en cours...';
    return 'Cliquez pour parler';
  }

  getConfidenceColor(): string {
    if (this.voiceState.confidence > 0.8) return 'text-success';
    if (this.voiceState.confidence > 0.6) return 'text-warning';
    return 'text-danger';
  }

  getConfidencePercentage(): number {
    return Math.round(this.voiceState.confidence * 100);
  }
}
<div class="voice-assistant p-4 bg-light rounded-4 shadow-sm">
  <!-- Header -->
  <div class="text-center mb-4">
    <h5 class="mb-2">
      <i class="bi bi-mic-fill text-primary me-2"></i>
      Assistant Vocal
    </h5>
    <p class="text-muted small mb-0">
      {{ getVoiceStatus() }}
    </p>
  </div>

  <!-- Audio Visualizer -->
  <div class="text-center mb-4">
    <div #audioVisualizer 
         class="audio-visualizer mx-auto d-flex align-items-center justify-content-center"
         [class.listening]="voiceState.isListening"
         [class.processing]="voiceState.isProcessing"
         [class.speaking]="voiceState.isSpeaking">

      <!-- Main Mic Button -->
      <button class="mic-button"
              [disabled]="!isSupported"
              (click)="toggleListening()"
              [title]="getVoiceStatus()">
        <i class="bi" [class]="getVoiceIcon()"></i>
      </button>

      <!-- Voice Waves Animation -->
      <div *ngIf="voiceState.isListening" class="voice-waves">
        <span class="wave"></span>
        <span class="wave"></span>
        <span class="wave"></span>
      </div>
    </div>

    <!-- Confidence Indicator -->
    <div *ngIf="voiceState.isListening && voiceState.confidence > 0" class="mt-2">
      <small [class]="getConfidenceColor()">
        <i class="bi bi-signal me-1"></i>
        Confiance: {{ (voiceState.confidence * 100 | number:'0.0-0') }}%
      </small>
    </div>
  </div>

  <!-- Transcript Display -->
  <div class="transcript-container mb-4">
    <!-- Partial Transcript (real-time) -->
    <div *ngIf="voiceState.partialTranscript" 
         class="partial-transcript mb-2 p-2 bg-white rounded border">
      <small class="text-muted">En cours...</small>
      <p class="mb-0 fst-italic">{{ voiceState.partialTranscript }}</p>
    </div>

    <!-- Final Transcript -->
    <div *ngIf="voiceState.transcript" 
         class="final-transcript p-3 bg-white rounded border">
      <div class="d-flex justify-content-between align-items-start mb-2">
        <small class="text-muted">Message:</small>
        <div class="btn-group btn-group-sm">
          <button class="btn btn-outline-primary btn-sm"
                  (click)="sendNow()"
                  [disabled]="voiceState.isProcessing"
                  title="Envoyer maintenant">
            <i class="bi bi-send-fill"></i>
          </button>
          <button class="btn btn-outline-secondary btn-sm"
                  (click)="clearTranscript()"
                  title="Effacer">
            <i class="bi bi-trash"></i>
          </button>
        </div>
      </div>
      <p class="mb-0">{{ voiceState.transcript }}</p>
    </div>
  </div>

  <!-- Controls -->
  <div class="controls mb-3">
    <div class="row g-2">
      <div class="col-6">
        <div class="form-check form-switch">
          <input class="form-check-input" 
                 type="checkbox" 
                 id="autoSend" 
                 [(ngModel)]="autoSend">
          <label class="form-check-label small" for="autoSend">
            Envoi automatique
          </label>
        </div>
      </div>
      <div class="col-6">
        <div class="form-check form-switch">
          <input class="form-check-input" 
                 type="checkbox" 
                 id="autoSpeak" 
                 [(ngModel)]="autoSpeak">
          <label class="form-check-label small" for="autoSpeak">
            Réponse vocale
          </label>
        </div>
      </div>
    </div>
  </div>

  <!-- Action Buttons -->
  <div class="action-buttons">
    <div class="row g-2">
      <div class="col-6">
        <button class="btn btn-outline-secondary btn-sm w-100"
                (click)="stopListening()"
                [disabled]="!voiceState.isListening">
          <i class="bi bi-stop-fill me-1"></i>
          Arrêter
        </button>
      </div>
      <div class="col-6">
        <button class="btn btn-outline-danger btn-sm w-100"
                (click)="stopSpeaking()"
                [disabled]="!voiceState.isSpeaking">
          <i class="bi bi-volume-mute-fill me-1"></i>
          Silencer
        </button>
      </div>
    </div>
  </div>

  <!-- Status Messages -->
  <div *ngIf="voiceState.isProcessing" class="mt-3 text-center">
    <div class="d-inline-flex align-items-center text-warning">
      <span class="spinner-border spinner-border-sm me-2" role="status"></span>
      <small>Traitement de votre demande...</small>
    </div>
  </div>

  <!-- Browser Support Warning -->
  <div *ngIf="!isSupported" class="alert alert-warning small">
    <i class="bi bi-exclamation-triangle me-2"></i>
    La reconnaissance vocale n'est pas supportée dans ce navigateur. 
    Utilisez Chrome, Edge ou Safari pour cette fonctionnalité.
  </div>
</div>
